from datetime import UTC, datetime
from types import SimpleNamespace

from sqlalchemy import or_, select, text
from sqlalchemy.orm import Session

from app.engines.topology.neighbor_collector import NeighborInfo, collect_cdp_neighbors, collect_lldp_neighbors
from app.models import Device, DeviceStatus, LinkProtocol, LinkStatus, NetworkLink, TopologyGroup, TopologyLayout
from app.services.device_service import create_device_with_monitor_sync


def _resolve_device(session: Session, neighbor: NeighborInfo) -> Device | None:
    if neighbor.remote_ip:
        device = session.execute(
            select(Device).where(Device.ip_address == neighbor.remote_ip)
        ).scalar_one_or_none()
        if device and device.status != DeviceStatus.RETIRED:
            return device

    if neighbor.remote_name:
        device = session.execute(
            select(Device).where(
                or_(
                    Device.hostname == neighbor.remote_name,
                    Device.hostname.ilike(neighbor.remote_name),
                )
            )
        ).scalar_one_or_none()
        if device and device.status != DeviceStatus.RETIRED:
            return device

        device = session.execute(
            select(Device).where(Device.hostname.ilike(f"%{neighbor.remote_name}%"))
        ).scalar_one_or_none()
        if device and device.status != DeviceStatus.RETIRED:
            return device
    return None


def register_neighbor_device(session: Session, neighbor: NeighborInfo) -> Device | None:
    if not neighbor.remote_ip:
        return None
    existing = session.execute(
        select(Device).where(Device.ip_address == neighbor.remote_ip)
    ).scalar_one_or_none()
    if existing:
        if existing.status == DeviceStatus.RETIRED:
            return None
        return existing
    return create_device_with_monitor_sync(
        session,
        ip_address=neighbor.remote_ip,
        hostname=neighbor.remote_name,
        device_type="network_device",
    )


def _upsert_link(
    session: Session,
    source: Device,
    neighbor: NeighborInfo,
    target: Device | None,
    edge_style: str = "smoothstep",
    map_layer: str = "physical",
) -> bool:
    protocol = LinkProtocol(neighbor.protocol) if neighbor.protocol != "manual" else LinkProtocol.MANUAL
    existing = session.execute(
        select(NetworkLink).where(
            NetworkLink.source_device_id == source.id,
            NetworkLink.source_port == neighbor.local_port,
            NetworkLink.remote_hostname == neighbor.remote_name,
        )
    ).scalar_one_or_none()

    if existing:
        existing.target_device_id = target.id if target else existing.target_device_id
        existing.target_port = neighbor.remote_port
        existing.remote_ip = neighbor.remote_ip
        existing.protocol = protocol
        existing.status = LinkStatus.ACTIVE
        existing.updated_at = datetime.now(UTC)
        session.add(existing)
        return False

    session.add(
        NetworkLink(
            source_device_id=source.id,
            target_device_id=target.id if target else None,
            source_port=neighbor.local_port,
            target_port=neighbor.remote_port,
            remote_hostname=neighbor.remote_name,
            remote_ip=neighbor.remote_ip,
            protocol=protocol,
            status=LinkStatus.ACTIVE,
            edge_style=edge_style,
            map_layer=map_layer,
        )
    )
    return True


def discover_topology_for_device(session: Session, device: Device, community: str | None = None) -> int:
    neighbors = collect_lldp_neighbors(device.ip_address, community)
    if not neighbors:
        neighbors = collect_cdp_neighbors(device.ip_address, community)

    created = 0
    for neighbor in neighbors:
        registered = register_neighbor_device(session, neighbor)
        target = registered or _resolve_device(session, neighbor)
        if _upsert_link(session, device, neighbor, target):
            created += 1
    return created


def _normalize_handles(
    source_handle: str | None,
    target_handle: str | None,
) -> tuple[str, str]:
    valid_source = {"right", "bottom"}
    valid_target = {"top", "left"}
    sh = source_handle if source_handle in valid_source else "right"
    th = target_handle if target_handle in valid_target else "left"
    return sh, th


def create_manual_link(
    session: Session,
    source_device_id: int,
    target_device_id: int,
    label: str | None = None,
    edge_style: str = "smoothstep",
    map_layer: str = "physical",
    source_handle: str | None = None,
    target_handle: str | None = None,
) -> NetworkLink:
    source = session.get(Device, source_device_id)
    target = session.get(Device, target_device_id)
    if not source or not target:
        raise ValueError("Dispositivo origem ou destino não encontrado")

    sh, th = _normalize_handles(source_handle, target_handle)

    existing_id = session.execute(
        text(
            """
            SELECT id FROM network_links
            WHERE map_layer = :layer AND lower(protocol::text) = 'manual'
              AND source_device_id = :src AND target_device_id = :tgt
            LIMIT 1
            """
        ),
        {"layer": map_layer, "src": source.id, "tgt": target.id},
    ).scalar_one_or_none()
    if existing_id:
        session.execute(
            text(
                """
                UPDATE network_links
                SET source_handle = :sh, target_handle = :th, edge_style = :style
                WHERE id = :id
                """
            ),
            {"sh": sh, "th": th, "style": edge_style, "id": existing_id},
        )
        return SimpleNamespace(id=existing_id)

    reverse_id = session.execute(
        text(
            """
            SELECT id FROM network_links
            WHERE map_layer = :layer AND lower(protocol::text) = 'manual'
              AND source_device_id = :tgt AND target_device_id = :src
            LIMIT 1
            """
        ),
        {"layer": map_layer, "src": source.id, "tgt": target.id},
    ).scalar_one_or_none()
    if reverse_id:
        session.execute(
            text(
                """
                UPDATE network_links
                SET source_device_id = :src, target_device_id = :tgt,
                    source_handle = :sh, target_handle = :th, edge_style = :style
                WHERE id = :id
                """
            ),
            {"src": source.id, "tgt": target.id, "sh": sh, "th": th, "style": edge_style, "id": reverse_id},
        )
        return SimpleNamespace(id=reverse_id)

    link_id = session.execute(
        text(
            """
            INSERT INTO network_links
                (source_device_id, target_device_id, source_port, protocol, status,
                 edge_style, map_layer, source_handle, target_handle)
            VALUES
                (:src, :tgt, :port, 'manual'::link_protocol, 'ACTIVE'::link_status,
                 :style, :layer, :sh, :th)
            RETURNING id
            """
        ),
        {
            "src": source.id,
            "tgt": target.id,
            "port": label or "manual",
            "style": edge_style,
            "layer": map_layer,
            "sh": sh,
            "th": th,
        },
    ).scalar_one()
    return SimpleNamespace(id=link_id)


def delete_manual_link(session: Session, link_id: int) -> None:
    deleted = session.execute(
        text(
            "DELETE FROM network_links WHERE id = :id AND lower(protocol::text) = 'manual' RETURNING id"
        ),
        {"id": link_id},
    ).scalar_one_or_none()
    if not deleted:
        raise ValueError("Link não encontrado")


def create_manual_group_link(
    session: Session,
    source_group_id: int,
    target_group_id: int,
    edge_style: str = "smoothstep",
    map_layer: str = "physical",
    source_handle: str | None = None,
    target_handle: str | None = None,
) -> SimpleNamespace:
    from app.models import GroupType

    source = session.get(TopologyGroup, source_group_id)
    target = session.get(TopologyGroup, target_group_id)
    if not source or not target:
        raise ValueError("Departamento origem ou destino não encontrado")
    if source.group_type != GroupType.DEPARTMENT or target.group_type != GroupType.DEPARTMENT:
        raise ValueError("Só é possível ligar departamentos")
    if source.id == target.id:
        raise ValueError("Não é possível ligar um departamento a si mesmo")

    sh, th = _normalize_handles(source_handle, target_handle)

    existing_id = session.execute(
        text(
            """
            SELECT id FROM topology_group_links
            WHERE map_layer = :layer
              AND source_group_id = :src AND target_group_id = :tgt
            LIMIT 1
            """
        ),
        {"layer": map_layer, "src": source.id, "tgt": target.id},
    ).scalar_one_or_none()
    if existing_id:
        session.execute(
            text(
                """
                UPDATE topology_group_links
                SET source_handle = :sh, target_handle = :th, edge_style = :style
                WHERE id = :id
                """
            ),
            {"sh": sh, "th": th, "style": edge_style, "id": existing_id},
        )
        return SimpleNamespace(id=existing_id)

    reverse_id = session.execute(
        text(
            """
            SELECT id FROM topology_group_links
            WHERE map_layer = :layer
              AND source_group_id = :tgt AND target_group_id = :src
            LIMIT 1
            """
        ),
        {"layer": map_layer, "src": source.id, "tgt": target.id},
    ).scalar_one_or_none()
    if reverse_id:
        session.execute(
            text(
                """
                UPDATE topology_group_links
                SET source_group_id = :src, target_group_id = :tgt,
                    source_handle = :sh, target_handle = :th, edge_style = :style
                WHERE id = :id
                """
            ),
            {"src": source.id, "tgt": target.id, "sh": sh, "th": th, "style": edge_style, "id": reverse_id},
        )
        return SimpleNamespace(id=reverse_id)

    link_id = session.execute(
        text(
            """
            INSERT INTO topology_group_links
                (source_group_id, target_group_id, edge_style, map_layer,
                 source_handle, target_handle, status)
            VALUES
                (:src, :tgt, :style, :layer, :sh, :th, 'ACTIVE'::link_status)
            RETURNING id
            """
        ),
        {
            "src": source.id,
            "tgt": target.id,
            "style": edge_style,
            "layer": map_layer,
            "sh": sh,
            "th": th,
        },
    ).scalar_one()
    return SimpleNamespace(id=link_id)


def delete_manual_group_link(session: Session, link_id: int) -> None:
    deleted = session.execute(
        text("DELETE FROM topology_group_links WHERE id = :id RETURNING id"),
        {"id": link_id},
    ).scalar_one_or_none()
    if not deleted:
        raise ValueError("Link não encontrado")


def infer_gateway_links(session: Session) -> int:
    created = 0
    devices = session.execute(
        select(Device).where(Device.status != DeviceStatus.RETIRED)
    ).scalars().all()

    subnets: dict[str, Device | None] = {}
    for device in devices:
        parts = device.ip_address.split(".")
        if len(parts) != 4:
            continue
        subnet = ".".join(parts[:3])
        if device.device_type == "router" or device.ip_address.endswith(".1"):
            subnets[subnet] = device

    for device in devices:
        parts = device.ip_address.split(".")
        if len(parts) != 4:
            continue
        subnet = ".".join(parts[:3])
        gateway = subnets.get(subnet)
        if not gateway or gateway.id == device.id:
            continue

        neighbor = NeighborInfo(
            local_port="default",
            remote_name=gateway.hostname or gateway.ip_address,
            remote_port=None,
            remote_ip=gateway.ip_address,
            protocol="inferred",
        )
        if _upsert_link(session, device, neighbor, gateway):
            created += 1
    return created


def _device_passes_filter(
    device: Device,
    device_type: str | None,
    status: str | None,
    tag: str | None,
) -> bool:
    if device_type and (device.device_type or "unknown") != device_type:
        return False
    if status and device.status.value != status:
        return False
    if tag:
        tags = device.tags or []
        if tag not in tags:
            return False
    return True


def _compute_department_health(devices: list[Device]) -> dict:
    """Calcula status operacional do departamento com base nos devices."""
    if not devices:
        return {
            "status": "empty",
            "device_count": 0,
            "online_count": 0,
            "offline_count": 0,
            "was_ever_online": False,
        }

    online = [d for d in devices if d.status == DeviceStatus.ACTIVE]
    offline = [d for d in devices if d.status != DeviceStatus.ACTIVE]
    was_ever_online = any(d.last_seen is not None or d.status == DeviceStatus.ACTIVE for d in devices)

    if len(online) == len(devices):
        dept_status = "online"
    elif len(offline) == len(devices):
        dept_status = "offline"
    elif was_ever_online:
        dept_status = "alert"
    else:
        dept_status = "offline"

    return {
        "status": dept_status,
        "device_count": len(devices),
        "online_count": len(online),
        "offline_count": len(offline),
        "was_ever_online": was_ever_online,
    }


