import { useCallback, useEffect, useMemo, useState } from "react";
import {
  Activity,
  CheckCircle2,
  Plus,
  Radar,
  Square,
  Upload,
  Wifi,
  WifiOff,
} from "lucide-react";
import {
  createDevice,
  clearToken,
  fetchDevice,
  fetchDeviceHistory,
  enrichDevice,
  fetchDevices,
  fetchDiscoveryJobs,
  fetchEvents,
  fetchScanDefaults,
  importCsv,
  startDiscovery,
  stopDiscoveryJob,
  DEFAULT_SCAN_OPTIONS,
  type Device,
  type DeviceHistoryEntry,
  type DiscoveryJob,
  type Event,
  type ScanDefaultsResponse,
  type ScanOptionsPayload,
} from "../api/client";
import DeviceList, { DeviceDetailPanel } from "../components/DeviceList";
import DeviceStatusChart from "../components/DeviceStatusChart";
import DeviceTypeBreakdown from "../components/DeviceTypeBreakdown";
import DiscoveryJobProgress, {
  DiscoveryJobActiveBanner,
  discoveryJobCounts,
} from "../components/DiscoveryJobProgress";
import DiscoveryScanOptions from "../components/DiscoveryScanOptions";
import StatCard from "../components/ui/StatCard";
import StatusBadge from "../components/ui/StatusBadge";
import DataTable, { type Column } from "../components/ui/DataTable";
import { useAuth } from "../context/AuthContext";

export default function Dashboard() {
  const { canWrite } = useAuth();
  const [devices, setDevices] = useState<Device[]>([]);
  const [events, setEvents] = useState<Event[]>([]);
  const [jobs, setJobs] = useState<DiscoveryJob[]>([]);
  const [ip, setIp] = useState("");
  const [hostname, setHostname] = useState("");
  const [subnet, setSubnet] = useState("192.168.1.0/24");
  const [message, setMessage] = useState<{ type: "success" | "error" | "info"; text: string } | null>(null);
  const [loading, setLoading] = useState(true);
  const [selectedDevice, setSelectedDevice] = useState<Device | null>(null);
  const [deviceHistory, setDeviceHistory] = useState<DeviceHistoryEntry[]>([]);
  const [enrichingDevice, setEnrichingDevice] = useState(false);
  const [stoppingJobId, setStoppingJobId] = useState<number | null>(null);
  const [trackedJobId, setTrackedJobId] = useState<number | null>(null);
  const [startingScan, setStartingScan] = useState(false);
  const [scanOptions, setScanOptions] = useState<ScanOptionsPayload>(DEFAULT_SCAN_OPTIONS);
  const [scanDefaults, setScanDefaults] = useState<ScanDefaultsResponse | null>(null);

  const pollDiscoveryJobs = useCallback(async () => {
    try {
      const jobList = await fetchDiscoveryJobs();
      setJobs(jobList);
    } catch {
      /* ignore poll errors */
    }
  }, []);

  const loadData = useCallback(async () => {
    const maxAttempts = 2;
    let lastError: unknown;
    for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
      try {
        const [deviceList, eventList, jobList] = await Promise.all([
          fetchDevices({ onMap: true }),
          fetchEvents(),
          fetchDiscoveryJobs(),
        ]);
        setDevices(deviceList);
        setEvents(eventList);
        setJobs(jobList);
        return;
      } catch (err) {
        lastError = err;
        const status = (err as Error & { status?: number }).status;
        const msg = err instanceof Error ? err.message : String(err);
        if (status === 401 || msg.includes("401") || msg.toLowerCase().includes("unauthorized")) {
          throw err;
        }
        if (attempt < maxAttempts) {
          await new Promise((resolve) => setTimeout(resolve, 1000));
        }
      }
    }
    throw lastError;
  }, []);

  useEffect(() => {
    const loadingCap = window.setTimeout(() => setLoading(false), 20000);
    loadData()
      .catch((err: unknown) => {
        const status = (err as Error & { status?: number }).status;
        const msg = err instanceof Error ? err.message : String(err);
        if (status === 401 || msg.includes("401") || msg.toLowerCase().includes("unauthorized")) {
          clearToken();
          setMessage({ type: "info", text: "Sessão expirada. Faça login novamente." });
          window.setTimeout(() => window.location.reload(), 1200);
          return;
        }
        setMessage({
          type: "error",
          text: "Erro ao carregar dados. Verifique se a API está online (http://localhost:8000/health).",
        });
      })
      .finally(() => {
        window.clearTimeout(loadingCap);
        setLoading(false);
      });
    const interval = setInterval(() => loadData().catch(() => undefined), 15000);
    return () => {
      window.clearTimeout(loadingCap);
      clearInterval(interval);
    };
  }, [loadData]);

  const activeJobs = useMemo(
    () => jobs.filter((j) => j.status === "pending" || j.status === "running"),
    [jobs],
  );

  const trackedJob = useMemo(
    () => (trackedJobId ? jobs.find((j) => j.id === trackedJobId) ?? null : null),
    [jobs, trackedJobId],
  );

  const bannerJobs = useMemo(() => {
    if (trackedJob) return [trackedJob];
    return activeJobs;
  }, [trackedJob, activeJobs]);

  const scanBusy = startingScan || activeJobs.length > 0 || trackedJobId !== null;

  useEffect(() => {
    fetchScanDefaults()
      .then(setScanDefaults)
      .catch(() => undefined);
  }, []);

  useEffect(() => {
    if (!trackedJobId && activeJobs.length === 0) return undefined;
    void pollDiscoveryJobs();
    const tick = window.setInterval(() => {
      void pollDiscoveryJobs();
    }, 1500);
    return () => window.clearInterval(tick);
  }, [trackedJobId, activeJobs.length, pollDiscoveryJobs]);

  useEffect(() => {
    if (!trackedJob) return undefined;
    if (trackedJob.status === "completed") {
      setMessage({ type: "success", text: `Scan #${trackedJob.id} concluído · ${trackedJob.subnet}` });
      void loadData();
      const t = window.setTimeout(() => setTrackedJobId(null), 6000);
      return () => window.clearTimeout(t);
    }
    if (trackedJob.status === "failed") {
      setMessage({
        type: "error",
        text: trackedJob.error_message ?? `Scan #${trackedJob.id} falhou.`,
      });
      const t = window.setTimeout(() => setTrackedJobId(null), 6000);
      return () => window.clearTimeout(t);
    }
    return undefined;
  }, [trackedJob?.status, trackedJob?.id, trackedJob?.subnet, trackedJob?.error_message, loadData]);

  const online = devices.filter((d) => d.status === "active").length;
  const offline = devices.filter((d) => d.status === "inactive").length;

  const handleStopDiscovery = useCallback(async (jobId: number) => {
    setStoppingJobId(jobId);
    try {
      const updated = await stopDiscoveryJob(jobId);
      setJobs((current) => current.map((j) => (j.id === updated.id ? updated : j)));
      setTrackedJobId(jobId);
      setMessage({ type: "info", text: `Scan #${jobId} cancelado.` });
    } catch {
      setMessage({ type: "error", text: "Erro ao cancelar scan." });
    } finally {
      setStoppingJobId(null);
    }
  }, [loadData]);

  const jobColumns: Column<DiscoveryJob>[] = useMemo(
    () => [
      { key: "id", header: "Job", render: (j) => `#${j.id}` },
      { key: "subnet", header: "Sub-rede", sortable: true },
      {
        key: "progress",
        header: "Progresso",
        render: (j) => <DiscoveryJobProgress job={j} />,
      },
      { key: "status", header: "Status", render: (j) => <StatusBadge status={j.status} /> },
      {
        key: "total_hosts",
        header: "Total",
        sortable: true,
        render: (j) => discoveryJobCounts(j).total || "—",
      },
      {
        key: "devices_found",
        header: "Ativos",
        sortable: true,
        render: (j) => discoveryJobCounts(j).active,
      },
      {
        key: "devices_inactive",
        header: "Inativos",
        sortable: true,
        render: (j) => discoveryJobCounts(j).inactive,
      },
      { key: "devices_new", header: "Novos", sortable: true },
      { key: "devices_updated", header: "Atualizados", sortable: true },
      {
        key: "completed_at",
        header: "Concluído",
        render: (j) => (j.completed_at ? new Date(j.completed_at).toLocaleString("pt-BR") : "—"),
      },
      {
        key: "actions",
        header: "",
        sortable: false,
        render: (j) =>
          canWrite && (j.status === "pending" || j.status === "running") ? (
            <button
              type="button"
              className="sa-btn sa-btn-danger sa-btn-sm"
              disabled={stoppingJobId === j.id}
              onClick={(e) => {
                e.stopPropagation();
                handleStopDiscovery(j.id);
              }}
            >
              <Square size={14} fill="currentColor" />
              {stoppingJobId === j.id ? "Parando..." : "Stop"}
            </button>
          ) : null,
      },
    ],
    [canWrite, stoppingJobId, handleStopDiscovery],
  );

  async function handleDiscovery() {
    if (!subnet.trim() || scanBusy) return;
    setStartingScan(true);
    setMessage(null);
    try {
      const job = await startDiscovery(subnet.trim(), { scanOptions });
      setTrackedJobId(job.id);
      setJobs((prev) => [job, ...prev.filter((j) => j.id !== job.id)]);
      void pollDiscoveryJobs();
    } catch (err) {
      const status = (err as Error & { status?: number }).status;
      const msg = err instanceof Error ? err.message : String(err);
      if (status === 409 || msg.includes("409")) {
        setMessage({ type: "error", text: "Já existe um scan em andamento. Cancele-o antes de iniciar outro." });
      } else {
        setMessage({ type: "error", text: "Erro ao iniciar scan." });
      }
    } finally {
      setStartingScan(false);
    }
  }

  async function handleAddDevice() {
    if (!ip.trim()) return;
    try {
      await createDevice(ip.trim(), hostname.trim() || undefined);
      setIp("");
      setHostname("");
      setMessage({ type: "success", text: "Dispositivo adicionado com monitor de ping." });
      await loadData();
    } catch {
      setMessage({ type: "error", text: "Erro ao adicionar dispositivo." });
    }
  }

  async function handleImport(file: File | undefined) {
    if (!file) return;
    const result = await importCsv(file);
    setMessage({ type: "success", text: `Importados: ${result.imported}, ignorados: ${result.skipped}` });
    await loadData();
  }

  async function handleSelectDevice(device: Device) {
    setSelectedDevice(device);
    setEnrichingDevice(true);
    try {
      const [enriched, history] = await Promise.all([
        enrichDevice(device.id).catch(() => fetchDevice(device.id)),
        fetchDeviceHistory(device.id),
      ]);
      setSelectedDevice(enriched);
      setDeviceHistory(history);
      setDevices((current) => current.map((d) => (d.id === enriched.id ? enriched : d)));
    } catch {
      setMessage({ type: "error", text: "Erro ao carregar detalhes do dispositivo." });
    } finally {
      setEnrichingDevice(false);
    }
  }

  if (loading) {
    return (
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", gap: "0.75rem", padding: "3rem" }}>
        <span className="sa-spinner" />
        <span style={{ color: "var(--sa-text-muted)" }}>Carregando dashboard...</span>
      </div>
    );
  }

  return (
    <>
      {message && (
        <div className={`sa-alert sa-alert-${message.type === "error" ? "error" : message.type === "success" ? "success" : "info"}`}>
          {message.text}
