import { Square } from "lucide-react";
import type { DiscoveryJob } from "../api/client";

export interface DiscoveryJobCounts {
  total: number;
  active: number;
  inactive: number;
}

function parseProgressTotal(job: DiscoveryJob): number {
  const match = job.progress_label?.match(/(\d+)\/(\d+)/);
  if (match) return Number(match[2]);
  return job.devices_found || job.total_hosts || 0;
}

/** Totais do scan: total na sub-rede, ativos (respondendo) e inativos. */
export function discoveryJobCounts(job: DiscoveryJob): DiscoveryJobCounts {
  const total = job.total_hosts || parseProgressTotal(job) || job.hosts_processed || 0;
  const active = job.devices_found ?? 0;
  let inactive = job.devices_inactive ?? 0;
  if (inactive === 0 && job.status === "completed" && total > active) {
    inactive = total - active;
  }
  return { total, active, inactive };
}

/** Backend é a fonte de verdade para a barra de progresso. */
function jobProgressPercent(job: DiscoveryJob): number {
  if (job.status === "completed") return 100;
  return job.progress_percent ?? 0;
}

export default function DiscoveryJobProgress({ job }: { job: DiscoveryJob }) {
  const percent = jobProgressPercent(job);
  const isActive = job.status === "pending" || job.status === "running";

  return (
    <div className={`sa-job-progress ${isActive ? "sa-job-progress-active" : ""}`}>
      <div className="sa-job-progress-head">
        <span className="sa-job-progress-value">{percent}%</span>
        {isActive && <span className="sa-job-progress-pulse" aria-hidden />}
      </div>
      <div className="sa-job-progress-track">
        <div className="sa-job-progress-fill" style={{ width: `${percent}%` }} />
      </div>
      {job.progress_label && <div className="sa-job-progress-label">{job.progress_label}</div>}
    </div>
  );
}

interface DiscoveryJobActiveBannerProps {
  job: DiscoveryJob;
  onStop?: () => void;
  stopping?: boolean;
  canStop?: boolean;
}

export function DiscoveryJobActiveBanner({
  job,
  onStop,
  stopping = false,
  canStop = false,
}: DiscoveryJobActiveBannerProps) {
  const percent = jobProgressPercent(job);
  const { total, active, inactive } = discoveryJobCounts(job);
  const profileLabel =
    job.scan_options?.profile &&
    ({
      quick: "Rápido",
      standard: "Padrão",
      deep: "Profundo",
      aggressive: "Agressivo",
      custom: "Personalizado",
    }[job.scan_options.profile] ?? job.scan_options.profile);
  const phase =
    job.status === "pending"
      ? "Na fila"
      : job.status === "completed"
        ? "Scan concluído"
        : job.status === "failed"
          ? "Scan falhou"
          : profileLabel
            ? `Scan nmap (${profileLabel})`
            : job.use_snmp
              ? "Scan nmap/SNMP em andamento"
              : "Scan em andamento";

  return (
    <div className="sa-job-active-banner">
      <div className="sa-job-active-banner-head">
        <div>
          <strong>{phase}</strong>
          <span>
            Job #{job.id} · {job.subnet}
            {total > 0 ? ` · ${total} total · ${active} ativos · ${inactive} inativos` : ""}
          </span>
        </div>
        <div className="sa-job-active-banner-actions">
          <span className="sa-job-active-banner-pct">{percent}%</span>
          {canStop && onStop && (
            <button
              type="button"
              className="sa-btn sa-btn-danger sa-btn-sm"
              disabled={stopping}
              onClick={onStop}
            >
              <Square size={14} fill="currentColor" />
              {stopping ? "Parando..." : "Stop"}
            </button>
          )}
        </div>
      </div>
      <div className="sa-job-progress-track sa-job-progress-track-lg">
        <div className="sa-job-progress-fill" style={{ width: `${percent}%` }} />
      </div>
      {job.progress_label && <p className="sa-job-active-banner-label">{job.progress_label}</p>}
    </div>
  );
}

