function edgePairKey(source: string, target: string): string {
  return source < target ? `${source}|${target}` : `${target}|${source}`;
}

function isGroupNodeId(id: string): boolean {
  return id.startsWith("group-");
}

function isGroupEdge(edge: Edge | Connection): boolean {
  return Boolean(
    edge.source && edge.target && isGroupNodeId(edge.source) && isGroupNodeId(edge.target),
  );
}

function resolveLinkId(edge: Edge): number | null {
  const fromData = edge.data?.linkId;
  if (typeof fromData === "number" && !Number.isNaN(fromData)) return fromData;
  const id = String(edge.id);
  if (id.startsWith("glink-")) {
    const parsed = parseInt(id.slice(6), 10);
    return Number.isNaN(parsed) ? null : parsed;
  }
  const parsed = parseInt(id, 10);
  return Number.isNaN(parsed) ? null : parsed;
}

function parseGraphEdgeLinkId(id: string): number | undefined {
  if (id.startsWith("glink-")) {
    const parsed = parseInt(id.slice(6), 10);
    return Number.isNaN(parsed) ? undefined : parsed;
  }
  const parsed = parseInt(id, 10);
  return Number.isNaN(parsed) ? undefined : parsed;
}

const SOURCE_HANDLES = new Set(["right", "bottom"]);
const TARGET_HANDLES = new Set(["top", "left"]);

function normalizeHandle(handle: string | null | undefined, kind: "source" | "target"): string {
  const valid = kind === "source" ? SOURCE_HANDLES : TARGET_HANDLES;
  const fallback = kind === "source" ? "right" : "left";
  return handle && valid.has(handle) ? handle : fallback;
}

function inferEdgeHandles(
  sourceId: string,
  targetId: string,
  nodes: Node[],
): { sourceHandle: string; targetHandle: string } {
  const source = nodes.find((n) => n.id === sourceId);
  const target = nodes.find((n) => n.id === targetId);
  if (!source || !target) return { sourceHandle: "right", targetHandle: "left" };
  const dx = target.position.x - source.position.x;
  const dy = target.position.y - source.position.y;
  if (Math.abs(dy) >= Math.abs(dx)) {
    return dy >= 0
      ? { sourceHandle: "bottom", targetHandle: "top" }
      : { sourceHandle: "right", targetHandle: "left" };
  }
  return { sourceHandle: "right", targetHandle: "left" };
}

function pickConnectionHandles(
  connection: Connection,
  edges: Edge[],
): { sourceHandle: string; targetHandle: string } {
  let sourceHandle = normalizeHandle(connection.sourceHandle, "source");
  let targetHandle = normalizeHandle(connection.targetHandle, "target");

  if (
    edges.some(
      (e) =>
        e.source === connection.source &&
        e.target === connection.target &&
        e.sourceHandle === sourceHandle &&
        e.targetHandle === targetHandle,
    )
  ) {
    return { sourceHandle, targetHandle };
  }

  if (
    edges.some(
      (e) => e.source === connection.source && e.sourceHandle === sourceHandle && e.target !== connection.target,
    )
  ) {
    sourceHandle = sourceHandle === "right" ? "bottom" : "right";
  }

  if (
    edges.some(
      (e) => e.target === connection.target && e.targetHandle === targetHandle && e.source !== connection.source,
    )
  ) {
    targetHandle = targetHandle === "left" ? "top" : "left";
  }

  return { sourceHandle, targetHandle };
}

function dedupeEdges(edges: Edge[]): Edge[] {
  const seen = new Set<string>();
  const out: Edge[] = [];
  for (const edge of edges) {
    const key = edgePairKey(edge.source, edge.target);
    if (seen.has(key)) continue;
    seen.add(key);
    out.push(edge);
  }
  return out;
}

/** Centraliza os nós com zoom fixo 1 — cards sempre 168×96 px na tela (igual devices). */
function centerMapAtCardZoom(
  sourceNodes: Node[],
  setCenter: (x: number, y: number, options?: { zoom?: number; duration?: number }) => void,
) {
  if (!sourceNodes.length) return;
  let minX = Infinity;
  let minY = Infinity;
  let maxX = -Infinity;
  let maxY = -Infinity;
  for (const n of sourceNodes) {
    minX = Math.min(minX, n.position.x);
    minY = Math.min(minY, n.position.y);
    maxX = Math.max(maxX, n.position.x + MAP_CARD_WIDTH);
    maxY = Math.max(maxY, n.position.y + MAP_CARD_HEIGHT);
  }
  setCenter((minX + maxX) / 2, (minY + maxY) / 2, { zoom: 1, duration: 200 });
}

function graphToFlow(
  graph: TopologyGraph,
  edgeStyle: EdgeStyle,
  traffic: TrafficMap,
): { nodes: Node[]; edges: Edge[] } {
  const nodes: Node[] = graph.nodes.map((n) => {
    const isDepartment = Boolean(n.is_department);
    const isDevice = n.device_id != null;
    const isLegacyGroup = Boolean(n.is_group) && !isDepartment;
    const cardDims = isDepartment || isDevice ? MAP_CARD_NODE_DIMS : null;

    return {
      id: n.id,
      type: isDepartment ? "department" : isLegacyGroup ? "group" : "device",
      position: n.position,
      parentId: n.parentId ?? undefined,
      ...(cardDims
        ? {
            width: cardDims.width,
            height: cardDims.height,
            initialWidth: cardDims.initialWidth,
            initialHeight: cardDims.initialHeight,
          }
        : {}),
      data: {
        label: n.label,
        ip_address: n.ip_address,
        device_type: n.device_type,
        status: n.status,
        device_id: n.device_id,
        group_id: n.group_id,
        tags: n.tags,
        last_seen: n.last_seen ?? null,
        was_ever_online: n.was_ever_online ?? (Boolean(n.last_seen) || n.status === "active"),
        device_count: n.device_count,
        online_count: n.online_count,
        offline_count: n.offline_count,
        width: isLegacyGroup ? n.style?.width : undefined,
        height: isLegacyGroup ? n.style?.height : undefined,
        color: n.style?.color,
      },
      style: isLegacyGroup
        ? { width: n.style?.width ?? 300, height: n.style?.height ?? 200, zIndex: -1 }
        : cardDims
          ? { ...cardDims.style }
          : undefined,
    };
  });
  const edges: Edge[] = graph.edges.map((e) => {
    const t = traffic[e.id];
    const linkId = parseGraphEdgeLinkId(e.id);
    const inferred = inferEdgeHandles(e.source, e.target, nodes);
    const sourceHandle = normalizeHandle(e.source_handle ?? inferred.sourceHandle, "source");
    const targetHandle = normalizeHandle(e.target_handle ?? inferred.targetHandle, "target");
    return {
      id: e.id,
      source: e.source,
      target: e.target,
      sourceHandle,
      targetHandle,
      type: "traffic",
      selectable: true,
      deletable: true,
      focusable: true,
      data: {
        status: e.status,
        edgeStyle: e.edge_style || edgeStyle,
        bps_in: t?.bps_in ?? e.bps_in ?? 0,
        bps_out: t?.bps_out ?? e.bps_out ?? 0,
        util_pct: t?.util_pct ?? e.util_pct,
        linkId,
        sourceHandle,
        targetHandle,
      },
    };
  });
  return { nodes, edges: dedupeEdges(edges) };
}

function layoutDagre(nodes: Node[], edges: Edge[]): Node[] {
  const g = new dagre.graphlib.Graph();
  g.setDefaultEdgeLabel(() => ({}));
  g.setGraph({ rankdir: "TB", nodesep: 80, ranksep: 100 });
  nodes.filter((n) => n.type !== "group").forEach((n) => g.setNode(n.id, { width: 150, height: 80 }));
  edges.forEach((e) => g.setEdge(e.source, e.target));
  dagre.layout(g);
  return nodes.map((n) => {
    if (n.type === "group") return n;
    const pos = g.node(n.id);
    if (!pos) return n;
    return { ...n, position: { x: pos.x - 75, y: pos.y - 40 } };
  });
}

