import { useMemo } from "react";
import type { TopologyGraph } from "../../api/client";

interface Map3DViewProps {
  graph: TopologyGraph;
}

function nodePos(node: { position: { x: number; y: number } }, bx: { minX: number; minY: number; w: number; h: number }) {
  const nx = ((node.position.x - bx.minX) / bx.w) * 80 - 40;
  const nz = ((node.position.y - bx.minY) / bx.h) * 80 - 40;
  return { nx, nz };
}

export default function Map3DView({ graph }: Map3DViewProps) {
  const { nodes, edges, posById } = useMemo(() => {
    const deviceNodes = graph.nodes.filter((n) => !n.is_group);
    if (!deviceNodes.length) {
      return { nodes: [], edges: [], bounds: { w: 1, h: 1, minX: 0, minY: 0 }, posById: new Map<string, { nx: number; nz: number; h: number }>() };
    }

    const xs = deviceNodes.map((n) => n.position.x);
    const ys = deviceNodes.map((n) => n.position.y);
    const minX = Math.min(...xs);
    const maxX = Math.max(...xs);
    const minY = Math.min(...ys);
    const maxY = Math.max(...ys);
    const bx = { w: Math.max(maxX - minX, 1), h: Math.max(maxY - minY, 1), minX, minY, maxX, maxY };

    const posById = new Map<string, { nx: number; nz: number; h: number }>();
    for (const node of deviceNodes) {
      const { nx, nz } = nodePos(node, bx);
      const h = node.status === "active" ? 24 : node.status === "inactive" ? 8 : 16;
      posById.set(node.id, { nx, nz, h });
    }

    return { nodes: deviceNodes, edges: graph.edges, bounds: bx, posById };
  }, [graph]);

  if (!nodes.length) {
    return <p className="sa-empty">Sem dispositivos para visualização 3D.</p>;
  }

  return (
    <div className="sa-map-3d-scene">
      <div className="sa-map-3d-floor" />
      <svg className="sa-map-3d-links" viewBox="-50 -50 100 100" preserveAspectRatio="xMidYMid meet">
        {edges.map((edge) => {
          const src = posById.get(edge.source);
          const tgt = posById.get(edge.target);
          if (!src || !tgt) return null;
          const active = edge.status === "active";
          const hasTraffic = (edge.bps_out ?? 0) > 0;
          return (
            <line
              key={edge.id}
              x1={src.nx}
              y1={src.nz}
              x2={tgt.nx}
              y2={tgt.nz}
              className={`sa-map-3d-link ${active ? "sa-map-3d-link-active" : ""} ${hasTraffic ? "sa-map-3d-link-traffic" : ""}`}
            />
          );
        })}
      </svg>
      {nodes.map((node, i) => {
        const pos = posById.get(node.id)!;
        const color =
          node.status === "active" ? "var(--sa-success)" : node.status === "inactive" ? "var(--sa-danger)" : "var(--sa-warning)";
        return (
          <div
            key={node.id}
            className={`sa-map-3d-node ${node.status === "inactive" ? "sa-map-3d-node-down" : ""}`}
            style={{
              transform: `translate3d(calc(50% + ${pos.nx}vw), ${-pos.h}px, ${pos.nz}px)`,
              height: `${pos.h}px`,
              background: color,
              animationDelay: `${i * 0.05}s`,
            }}
            title={`${node.label} (${node.ip_address ?? ""})`}
          >
            <span>{node.label?.slice(0, 12)}</span>
          </div>
        );
      })}
      <p className="sa-map-3d-hint">Vista 3D isométrica · links animados com tráfego</p>
    </div>
  );
}

