export function formatApiError(err: unknown): string {
  if (err instanceof DOMException && (err.name === "TimeoutError" || err.name === "AbortError")) {
    return "Tempo esgotado ao contactar a API. Verifique se o backend está ativo (porta 8000).";
  }
  if (err instanceof Error) {
    const msg = err.message;
    if (/signal timed out|TimeoutError|aborted due to timeout/i.test(msg)) {
      return "Tempo esgotado ao contactar a API. Verifique se o backend está ativo (porta 8000).";
    }
    if (msg === "Failed to fetch" || /NetworkError|network/i.test(msg)) {
      return "Não foi possível ligar à API. Confirme que o backend está a correr.";
    }
    return msg;
  }
  return String(err);
}

async function request<T>(path: string, options: RequestInit = {}): Promise<T> {
  const token = getToken();
  const headers: Record<string, string> = {
    ...(options.headers as Record<string, string> | undefined),
  };

  if (token) {
    headers.Authorization = `Bearer ${token}`;
  }

  if (!(options.body instanceof FormData)) {
    headers["Content-Type"] = headers["Content-Type"] ?? "application/json";
  }

  let response: Response;
  try {
    response = await fetch(`${API_BASE}${path}`, {
      ...options,
      headers,
      signal: options.signal ?? AbortSignal.timeout(12000),
    });
  } catch (err) {
    throw new Error(formatApiError(err));
  }

  if (!response.ok) {
    const text = await response.text();
    const err = new Error(text || `Erro ${response.status}`);
    (err as Error & { status?: number }).status = response.status;
    throw err;
  }

  if (response.status === 204) {
    return undefined as T;
  }

  return response.json() as Promise<T>;
}

export async function login(username: string, password: string): Promise<void> {
  const body = new URLSearchParams({ username, password });
  let response: Response;
  try {
    response = await fetch(`${API_BASE}/api/auth/login`, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body,
      signal: AbortSignal.timeout(15000),
    });
  } catch {
    throw new Error("Não foi possível conectar à API. Verifique se o serviço está online.");
  }

  if (response.status === 401) {
    throw new Error("Usuário ou senha inválidos");
  }
  if (!response.ok) {
    throw new Error(`Erro no login (${response.status}). Tente novamente.`);
  }

  const data = (await response.json()) as { access_token: string };
  setToken(data.access_token);
}

