@dataclass
class AlertPayload:
    subject: str
    body: str
    severity: str
    event_type: str


async def send_telegram(payload: AlertPayload) -> bool:
    if not settings.telegram_bot_token or not settings.telegram_chat_id:
        return False
    text = f"🚨 *{payload.subject}*\n\n{payload.body}\n\n_Severidade: {payload.severity}_"
    url = f"https://api.telegram.org/bot{settings.telegram_bot_token}/sendMessage"
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.post(url, json={"chat_id": settings.telegram_chat_id, "text": text, "parse_mode": "Markdown"})
            return r.status_code == 200
    except Exception as exc:
        logger.error("Telegram alert failed: %s", exc)
        return False


async def send_discord(payload: AlertPayload) -> bool:
    if not settings.discord_webhook_url:
        return False
    color = {"critical": 0xDC2626, "warning": 0xD97706, "info": 0x2563EB}.get(payload.severity, 0x64748B)
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.post(
                settings.discord_webhook_url,
                json={
                    "embeds": [{
                        "title": payload.subject,
                        "description": payload.body,
                        "color": color,
                        "footer": {"text": f"SentinelAI · {payload.event_type}"},
                    }]
                },
            )
            return r.status_code in (200, 204)
    except Exception as exc:
        logger.error("Discord alert failed: %s", exc)
        return False


async def send_slack(payload: AlertPayload) -> bool:
    if not settings.slack_webhook_url:
        return False
    emoji = {"critical": "🔴", "warning": "🟡", "info": "🟢"}.get(payload.severity, "ℹ️")
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.post(
                settings.slack_webhook_url,
                json={"text": f"{emoji} *{payload.subject}*\n{payload.body}"},
            )
            return r.status_code == 200
    except Exception as exc:
        logger.error("Slack alert failed: %s", exc)
        return False


async def send_teams(payload: AlertPayload) -> bool:
    if not settings.teams_webhook_url:
        return False
    theme = {"critical": "attention", "warning": "warning", "info": "good"}.get(payload.severity, "default")
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.post(
                settings.teams_webhook_url,
                json={
                    "@type": "MessageCard",
                    "@context": "http://schema.org/extensions",
                    "themeColor": theme,
                    "summary": payload.subject,
                    "sections": [{"activityTitle": payload.subject, "text": payload.body}],
                },
            )
            return r.status_code == 200
    except Exception as exc:
        logger.error("Teams alert failed: %s", exc)
        return False


async def send_webhook(payload: AlertPayload) -> bool:
    if not settings.generic_webhook_url:
        return False
    try:
        async with httpx.AsyncClient(timeout=10) as client:
            r = await client.post(
                settings.generic_webhook_url,
                json={
                    "source": "sentinelai",
                    "subject": payload.subject,
                    "body": payload.body,
                    "severity": payload.severity,
                    "event_type": payload.event_type,
                },
            )
            return r.status_code in (200, 201, 204)
    except Exception as exc:
        logger.error("Webhook alert failed: %s", exc)
        return False


CHANNEL_SENDERS = {
    "email": lambda p: send_email_alert(p.subject, p.body),
    "telegram": send_telegram,
    "discord": send_discord,
    "slack": send_slack,
    "teams": send_teams,
    "webhook": send_webhook,
}


async def dispatch_to_channel(channel: str, payload: AlertPayload) -> bool:
    sender = CHANNEL_SENDERS.get(channel)
    if not sender:
        return False
    try:
        return await sender(payload)
    except Exception as exc:
        logger.error("Channel %s failed: %s", channel, exc)
        return False
